# STATIC PAGES
# ═══════════════════════════════════════════════════════════════════════════════
def _repair_signals(sid, df):
    _ensure_sig_cols()
    sig_cols_db = _get_columns("signals") - {"session_id"}
    use_cols = [c for c in _ALL_SIG_COLS if c in sig_cols_db]
    for c in use_cols:
        if c not in df.columns: df[c] = np.nan
    sig = df[use_cols].copy()
    sig.insert(0, "session_id", sid)
    for c in sig.columns:
        if c in _TEXT_SIG_COLS:
            sig[c] = sig[c].where(pd.notna(sig[c]), other=None).astype(object)
        else:
            sig[c] = pd.to_numeric(sig[c], errors="coerce")
    with get_engine().connect() as con:
        con.execute(text("DELETE FROM signals WHERE session_id=:s"), {"s": sid})
        con.commit()
    sig.to_sql("signals", get_engine(), if_exists="append", index=False, chunksize=500)


def page_upload():
    shdr("NEW TEST SESSION")
    with st.form("upload_form"):
        c1, c2 = st.columns(2)

        name      = c1.text_input("Session name *", placeholder="Road Test 01 — EN125 Faro")
        date      = c1.date_input("Test date")

        # Motorcycle dropdown
        moto_opts = ["(select motorcycle)"] + MOTO_OPTIONS
        moto_sel  = c1.selectbox("Motorcycle on tests *", moto_opts)

        # Rider dropdown + custom entry
        rider_sel = c1.selectbox("Rider", RIDER_OPTIONS)
        rider_custom = ""
        if rider_sel == "Other":
            rider_custom = c1.text_input("Rider name (custom)", placeholder="Enter rider name")

        firmware  = c2.text_input("Firmware version", placeholder="v2.4.1")
        config    = c2.text_input("Setup / config changes", placeholder="Standard, tyre 2.5bar")
        ambient_t = c2.number_input("Ambient temp (°C)", value=20.0, step=0.5)
        weather   = c2.selectbox("Weather", WEATHER_OPTIONS)
        track     = c2.text_input("Road / Location", placeholder="EN125 Faro → Loulé")
        notes     = st.text_area("Engineering notes", placeholder="Test purpose, hypothesis, changes since last run…", height=80)
        f         = st.file_uploader("CSV log file *", type=["csv"])
        ok        = st.form_submit_button("💾 Save to database", type="primary", use_container_width=True)

    if ok:
        if not name: st.error("Session name required."); return
        if moto_sel == "(select motorcycle)": st.error("Select a motorcycle."); return
        if f is None: st.error("Select a CSV file."); return
        rider_final = rider_custom.strip() if rider_sel == "Other" else rider_sel
        with st.spinner("Parsing and uploading…"):
            try:
                raw_bytes = f.read()
                df, start_hms = parse_csv(raw_bytes)
                df = derive(df)
                dur = float(df["t"].max()) if df["t"].notna().any() else 0.0

                existing = load_sessions()
                match = existing[existing["name"] == name] if not existing.empty else pd.DataFrame()

                if not match.empty:
                    sid = int(match.iloc[0]["id"])
                    with get_engine().connect() as con:
                        res = con.execute(text("SELECT COUNT(*) FROM signals WHERE session_id=:s"), {"s": sid})
                        existing_rows = res.fetchone()[0]
                    if existing_rows == 0:
                        _repair_signals(sid, df)
                        bust()
                        with get_engine().connect() as con:
                            res = con.execute(text("SELECT COUNT(*) FROM signals WHERE session_id=:s"), {"s": sid})
                            actual_rows = res.fetchone()[0]
                        st.success(f"🔧 **Repaired '{name}'** — wrote {actual_rows:,} signal rows to session ID {sid}")
                    else:
                        st.info(f"ℹ️ Session **'{name}'** already exists with {existing_rows:,} rows. Rename to create a new entry, or delete the old session first.")
                    bust()
                else:
                    sid = save_db(dict(name=name, date=str(date), rider=rider_final,
                        track=track, weather=weather, notes=notes, firmware=firmware,
                        config=config, ambient_temp=float(ambient_t),
                        upload_time=datetime.now().isoformat(), row_count=len(df),
                        duration_s=dur, start_hms=start_hms, motorcycle=moto_sel), df)
                    bust()
                    with get_engine().connect() as con:
                        res = con.execute(text("SELECT COUNT(*) FROM signals WHERE session_id=:s"), {"s": sid})
                        actual_rows = res.fetchone()[0]
                    if actual_rows == 0:
                        st.error(f"❌ Upload failed silently — 0 rows in DB for session ID {sid}.")
                    else:
                        st.success(f"✅ **'{name}'** saved — {actual_rows:,} rows · {dur:.0f}s ({dur/60:.1f} min) · Start {start_hms}")
            except Exception as e:
                st.error(f"❌ Upload error: {e}")


def page_sessions():
    shdr("SESSION LIBRARY")
    sess = load_sessions()
    if sess.empty: st.info("No sessions yet."); return
    c1,c2,c3,c4 = st.columns(4)
    c1.metric("Sessions", len(sess))
    c2.metric("Test time", f'{sess["duration_s"].sum()/3600:.1f} h')
    c3.metric("Data rows", f'{sess["row_count"].sum():,}')
    c4.metric("Riders", sess["rider"].nunique())

    # Broken sessions check
    broken = []
    for _,r in sess.iterrows():
        with get_engine().connect() as con:
            res = con.execute(text("SELECT COUNT(*) FROM signals WHERE session_id=:s"), {"s": int(r["id"])})
            n = res.fetchone()[0]
        if n == 0:
            broken.append((int(r["id"]), r["name"]))
    if broken:
        st.warning(
            f"⚠️ **{len(broken)} session(s) have no signal data**: "
            + ", ".join(f"*{name}*" for _,name in broken)
            + "\n\nTo fix: go to **Upload**, use the **exact same session name**, and re-upload the CSV.")
    st.divider()

    for _,r in sess.iterrows():
        dur = r["duration_s"]
        moto = r.get("motorcycle","") or "—"
        with st.expander(f'**{r["name"]}** · {r["date"]} · {r.get("rider","—") or "—"} · {moto}'):
            # Info row
            ca,cb,cc,cd,ce = st.columns(5)
            ca.markdown(f'**FW** {r.get("firmware","—") or "—"}')
            cb.markdown(f'**Config** {r.get("config","—") or "—"}')
            cc.markdown(f'**Duration** {dur:.0f}s / {dur/60:.1f}min')
            cd.markdown(f'**Ambient** {r.get("ambient_temp","—") or "—"}°C')
            ce.markdown(f'**Start** {r.get("start_hms","—") or "—"}')
            if r.get("weather"): st.markdown(f'**Weather:** {r["weather"]}')
            if r.get("notes"):   st.markdown(f'**Notes:** {r["notes"]}')

            # ── EDIT FORM (all fields except name) ─────────────────────────
            with st.expander("✏️ Edit session metadata"):
                with st.form(f"edit_{r['id']}"):
                    ec1, ec2 = st.columns(2)

                    e_date   = ec1.date_input("Test date",
                        value=datetime.strptime(str(r["date"]), "%Y-%m-%d").date() if r.get("date") else datetime.today().date(),
                        key=f"ed_{r['id']}")

                    # Motorcycle dropdown
                    cur_moto = r.get("motorcycle") or ""
                    moto_idx = MOTO_OPTIONS.index(cur_moto) if cur_moto in MOTO_OPTIONS else 0
                    moto_opts_edit = ["(select motorcycle)"] + MOTO_OPTIONS
                    e_moto = ec1.selectbox("Motorcycle on tests", moto_opts_edit,
                        index=moto_idx+1 if cur_moto else 0, key=f"em_{r['id']}")

                    # Rider
                    cur_rider = r.get("rider") or ""
                    rider_idx = RIDER_OPTIONS.index(cur_rider) if cur_rider in RIDER_OPTIONS else len(RIDER_OPTIONS)-1
                    e_rider_sel = ec1.selectbox("Rider", RIDER_OPTIONS, index=rider_idx, key=f"ers_{r['id']}")
                    e_rider_custom = ""
                    if e_rider_sel == "Other":
                        e_rider_custom = ec1.text_input("Rider name", value=cur_rider, key=f"erc_{r['id']}")

                    cur_weather = r.get("weather") or WEATHER_OPTIONS[0]
                    weather_idx = WEATHER_OPTIONS.index(cur_weather) if cur_weather in WEATHER_OPTIONS else 0
                    e_weather = ec1.selectbox("Weather", WEATHER_OPTIONS, index=weather_idx, key=f"ew_{r['id']}")
                    e_track   = ec1.text_input("Road / Location", value=r.get("track","") or "", key=f"et_{r['id']}")

                    e_fw      = ec2.text_input("Firmware version", value=r.get("firmware","") or "", key=f"efw_{r['id']}")
                    e_cfg     = ec2.text_input("Setup / config", value=r.get("config","") or "", key=f"ecfg_{r['id']}")
                    e_amb     = ec2.number_input("Ambient temp (°C)",
                        value=float(r["ambient_temp"]) if pd.notna(r.get("ambient_temp")) else 20.0,
                        step=0.5, key=f"eamb_{r['id']}")
                    e_notes   = st.text_area("Notes", value=r.get("notes","") or "", height=70, key=f"en_{r['id']}")

                    if st.form_submit_button("💾 Update", type="primary"):
                        rider_final = e_rider_custom.strip() if e_rider_sel == "Other" else e_rider_sel
                        moto_final  = e_moto if e_moto != "(select motorcycle)" else ""
                        with get_engine().connect() as con:
                            con.execute(text(
                                "UPDATE sessions SET date=:d, motorcycle=:m, rider=:ri, weather=:w, "
                                "track=:tr, firmware=:fw, config=:cfg, ambient_temp=:at, notes=:n "
                                "WHERE id=:id"),
                                dict(d=str(e_date), m=moto_final, ri=rider_final, w=e_weather,
                                     tr=e_track, fw=e_fw, cfg=e_cfg, at=e_amb, n=e_notes, id=int(r["id"])))
                            con.commit()
                        bust(); st.rerun()

            if st.button("🗑️ Delete", key=f'del_{r["id"]}'):
                with get_engine().connect() as con:
                    for tbl in ["signals","annotations","sessions"]:
                        con.execute(text(f'DELETE FROM {tbl} WHERE {"session_id" if tbl!="sessions" else "id"}=:id'),{"id":r["id"]})
                    con.commit()
                bust(); st.rerun()


def page_analyse(thr):
    shdr("SESSION ANALYSIS")
    sess = load_sessions()
    if sess.empty: st.info("No sessions yet."); return
    opts = {f'{r["name"]}  [{r["date"]}]': (int(r["id"]), r) for _,r in sess.iterrows()}
    label = st.selectbox("Select session", list(opts.keys()))
    sid, srow = opts[label]
    load_signals.clear()
    raw_df = load_signals(sid)
    df = derive(raw_df)

    if raw_df.empty or "t" not in raw_df.columns or raw_df["t"].notna().sum() == 0:
        n_rows = len(raw_df)
        st.error(
            f"**No signal data found for session ID {sid}** ({n_rows} rows in database).\n\n"
            "Please **delete this session** from Sessions and **re-upload the CSV**.")
        return

    raw_hms = srow.get("start_hms")
    shms_str = str(raw_hms) if raw_hms and str(raw_hms) not in ("nan","None","") else "00:00:00"
    start_hms = ":".join(shms_str.split(":")[:3])

    # Reset shared time window when session changes
    if st.session_state.get("_analyse_sid") != sid:
        st.session_state.pop("shared_tw_t0", None)
        st.session_state.pop("shared_tw_t1", None)
        st.session_state["_analyse_sid"] = sid

    tabs = st.tabs(["📊 Overview","⚙️ Powertrain","🔋 Battery","🌡️ Thermal","🔴 Faults","🗺️ Route","🤖 AI"])
    with tabs[0]: tab_overview(df, start_hms, thr, srow.to_dict())
    with tabs[1]: tab_powertrain(df, start_hms, thr)
    with tabs[2]: tab_battery(df, start_hms, thr)
    with tabs[3]: tab_thermal(df, start_hms, thr)
    with tabs[4]: tab_faults(df, start_hms, thr)
    with tabs[5]: tab_route(df, start_hms, sid)
    with tabs[6]: tab_ai(df, start_hms, srow.to_dict(), thr)


def page_compare(thr):
    shdr("SESSION COMPARISON")
    sess = load_sessions()
    if len(sess)<2: st.info("Upload at least 2 sessions."); return
    opts = {f'{r["name"]}  [{r["date"]}]': int(r["id"]) for _,r in sess.iterrows()}
    keys = list(opts.keys())
    c1,c2 = st.columns(2)
    la = c1.selectbox("Session A", keys, key="ca")
    lb = c2.selectbox("Session B", [k for k in keys if k!=la], key="cb")
    df_a = derive(load_signals(opts[la]))
    df_b = derive(load_signals(opts[lb]))
    avail = [k for k in list(CHANNELS.keys())+["power_kw"] if k in df_a.columns and k in df_b.columns]
    defs  = [c for c in ["motor_temp","soc_bms1","speed_kmh","curr_mcu","volt_mcu"] if c in avail]
    sel   = st.multiselect("Channels", avail, defs, format_func=lambda x:CHANNELS.get(x,x.replace("_"," ").title()))
    if not sel: return
    shdr("STATISTICS TABLE")
    rows=[]
    for ch in sel:
        va,vb = num(df_a,ch).dropna(),num(df_b,ch).dropna()
        if va.empty or vb.empty: continue
        d = vb.mean()-va.mean()
        rows.append({"Channel":CHANNELS.get(ch,ch),"A Min":f'{va.min():.2f}',"A Mean":f'{va.mean():.2f}',"A Max":f'{va.max():.2f}',
                     "B Min":f'{vb.min():.2f}',"B Mean":f'{vb.mean():.2f}',"B Max":f'{vb.max():.2f}',
                     "Δ Mean":f'{"↑" if d>0 else "↓"} {abs(d):.2f}'})
    st.dataframe(pd.DataFrame(rows), use_container_width=True, hide_index=True)
    shdr("SIGNAL OVERLAY")
    for ch in sel:
        fig = go.Figure()
        sa,sb = ds(df_a),ds(df_b)
        fig.add_trace(go.Scatter(x=sa["t"],y=num(sa,ch),name=f'A: {la[:30]}',line=dict(color="#58a6ff",width=1.8)))
        fig.add_trace(go.Scatter(x=sb["t"],y=num(sb,ch),name=f'B: {lb[:30]}',line=dict(color="#f7931a",width=1.8)))
        if ch in thr:
            fig.add_hline(y=thr[ch]["warn"],line_dash="dot",line_color="orange",opacity=0.4)
            fig.add_hline(y=thr[ch]["crit"],line_dash="dash",line_color="#ff4444",opacity=0.4)
        fig.update_layout(**plt({"height":240,"title":dict(text=CHANNELS.get(ch,ch),font=dict(size=12,color="#8b949e")),
            "xaxis_title":"Time (s)","legend":dict(bgcolor="rgba(22,27,34,.8)",bordercolor="#21262d",borderwidth=1,orientation="h",y=-0.3)}))
        st.plotly_chart(fig, use_container_width=True, config=SCROLLZOOM)


def page_paddock():
    """Fleet-level metrics across all motorcycles."""
    shdr("PADDOCK — FLEET OVERVIEW")
    sess = load_sessions()
    if sess.empty: st.info("No sessions yet."); return

    # ── Overall totals ────────────────────────────────────────────────────────
    total_km   = 0.0
    total_h    = sess["duration_s"].sum() / 3600
    total_sess = len(sess)

    # Load dist_km from signals for each session (cached)
    @st.cache_data(ttl=120)
    def _fleet_dist():
        rows = []
        all_s = pd.read_sql("SELECT * FROM sessions ORDER BY date DESC, id DESC", get_engine())
        for _, r in all_s.iterrows():
            sid = int(r["id"])
            try:
                d = pd.read_sql(f"SELECT MAX(dist_km) as d FROM (SELECT SUM(speed_kmh * 0.02 / 3600) OVER (ORDER BY t) as dist_km FROM signals WHERE session_id={sid} ORDER BY t) sub", get_engine())
                km = float(d.iloc[0]["d"]) if d.iloc[0]["d"] is not None else 0.0
            except:
                km = 0.0
            rows.append({"id": sid, "km": round(km, 2)})
        return pd.DataFrame(rows)

    dist_df = _fleet_dist()
    sess = sess.merge(dist_df, on="id", how="left")
    sess["km"] = sess["km"].fillna(0.0)
    total_km = sess["km"].sum()

    # Top summary KPIs
    kk = st.columns(4)
    kpi(kk[0], "Total Fleet km",   f'{total_km:.1f} km')
    kpi(kk[1], "Total Test Time",  f'{total_h:.1f} h')
    kpi(kk[2], "Total Sessions",   str(total_sess))
    kpi(kk[3], "Motorcycles Active", str(sess["motorcycle"].nunique()))
    st.markdown("<br>", unsafe_allow_html=True)

    # ── Per-motorcycle cards ──────────────────────────────────────────────────
    shdr("PER MOTORCYCLE STATS")
    moto_groups = sess.groupby("motorcycle")
    # Sort by total km desc
    moto_stats = []
    for moto, grp in moto_groups:
        moto_stats.append({
            "name":       moto or "Unknown",
            "sessions":   len(grp),
            "km":         grp["km"].sum(),
            "hours":      grp["duration_s"].sum() / 3600,
            "last_date":  grp["date"].max(),
            "riders":     grp["rider"].nunique(),
            "avg_km":     grp["km"].mean(),
        })
    moto_stats.sort(key=lambda x: x["km"], reverse=True)

    # Display 3 cards per row
    cols_per_row = 3
    for i in range(0, len(moto_stats), cols_per_row):
        cols = st.columns(cols_per_row)
        for j, ms in enumerate(moto_stats[i:i+cols_per_row]):
            with cols[j]:
                st.markdown(f'<div class="fleet-card">', unsafe_allow_html=True)
                # Motorcycle image
                img_html = moto_image_html(ms["name"], height=140)
                st.markdown(img_html, unsafe_allow_html=True)
                st.markdown(f'<div class="fleet-card-title">{ms["name"]}</div>', unsafe_allow_html=True)
                st.markdown(f'''
                <div class="fleet-stat-row">
                  <div class="fleet-stat"><div class="fleet-stat-val">{ms["km"]:.1f}</div><div class="fleet-stat-lbl">Total km</div></div>
                  <div class="fleet-stat"><div class="fleet-stat-val">{ms["sessions"]}</div><div class="fleet-stat-lbl">Sessions</div></div>
                  <div class="fleet-stat"><div class="fleet-stat-val">{ms["hours"]:.1f}h</div><div class="fleet-stat-lbl">Test Time</div></div>
                </div>
                <div class="fleet-stat-row" style="margin-top:6px;">
                  <div class="fleet-stat"><div class="fleet-stat-val">{ms["avg_km"]:.1f}</div><div class="fleet-stat-lbl">Avg km/sess</div></div>
                  <div class="fleet-stat"><div class="fleet-stat-val">{ms["riders"]}</div><div class="fleet-stat-lbl">Riders</div></div>
                  <div class="fleet-stat"><div class="fleet-stat-val" style="font-size:.85rem">{ms["last_date"] or "—"}</div><div class="fleet-stat-lbl">Last Test</div></div>
                </div>
                ''', unsafe_allow_html=True)
                st.markdown('</div>', unsafe_allow_html=True)

    # Sessions table per motorcycle
    st.markdown("<br>", unsafe_allow_html=True)
    shdr("SESSIONS BY MOTORCYCLE")
    if not sess.empty:
        disp = sess[["name","date","motorcycle","rider","duration_s","km","weather"]].copy()
        disp["duration_s"] = disp["duration_s"].apply(lambda x: f'{x/60:.1f} min' if pd.notna(x) else "—")
        disp["km"] = disp["km"].apply(lambda x: f'{x:.2f}')
        disp = disp.rename(columns={"name":"Session","date":"Date","motorcycle":"Motorcycle",
                                     "rider":"Rider","duration_s":"Duration","km":"km","weather":"Weather"})
        st.dataframe(disp, use_container_width=True, hide_index=True)


def page_ai_instructions():
    """Page for editing persistent AI system instructions."""
    shdr("AI INSTRUCTIONS — SYSTEM CONFIGURATION")
    st.caption("These instructions are injected into every AI conversation as additional system guidance. Use this to specify constraints, preferred analysis style, team conventions, etc.")

    current = load_ai_instructions()

    with st.form("ai_instr_form"):
        new_instr = st.text_area(
            "System instructions for the AI",
            value=current,
            height=320,
            placeholder=(
                "Example:\n"
                "- Always respond in European Portuguese.\n"
                "- Flag any motor temp above 100°C as a priority concern.\n"
                "- When reporting faults, always list the most critical first.\n"
                "- Assume the test team uses metric units.\n"
                "- Reference the FAMEL homologation standard when applicable."
            ),
            key="ai_instr_input"
        )
        save_btn = st.form_submit_button("💾 Save instructions", type="primary")

    if save_btn:
        save_ai_instructions(new_instr)
        st.success("✅ AI instructions saved. They will be used in all future AI conversations.")
        st.rerun()

    if current:
        st.markdown("<br>", unsafe_allow_html=True)
        shdr("CURRENT INSTRUCTIONS (active)")
        st.markdown(f'<div class="ann-box" style="white-space:pre-wrap;font-size:.82rem;">{current}</div>', unsafe_allow_html=True)

# ═══════════════════════════════════════════════════════════════════════════════
# MAIN — top navigation bar + logo
# ═══════════════════════════════════════════════════════════════════════════════
NAV_PAGES = [
    "📤 Upload",
    "📋 Sessions",
    "📊 Analyse",
    "🔄 Compare",
    "🏍️ Paddock",
    "⚙️ AI Config",
]

def _nav_logo_html(logo_b64):
    return f'<img src="data:image/png;base64,{logo_b64}" style="height:28px;margin-right:18px;vertical-align:middle;" />'

def main():
    # ── Init session state ───────────────────────────────────────────────────
    if "page" not in st.session_state:
        st.session_state.page = NAV_PAGES[0]

    logo_b64 = _MOTO_IMAGES.get("LOGO", "")

    # ── Top navigation bar ───────────────────────────────────────────────────
    # Stats for nav bar
    try:
        sess_all = load_sessions()
        n_sess = len(sess_all)
        h_logged = sess_all["duration_s"].sum() / 3600 if not sess_all.empty else 0
        nav_stats = f'<span class="nav-stat">{n_sess} sessions · {h_logged:.1f} h logged</span>'
    except:
        nav_stats = ""

    logo_html = _nav_logo_html(logo_b64) if logo_b64 else '<span style="color:#f7931a;font-family:Share Tech Mono,monospace;font-size:.9rem;margin-right:18px;">⚡ FAMEL</span>'

    # Render nav bar visual (HTML only — no interactivity)
    st.markdown(f"""
    <div class="top-nav">
        {logo_html}
        <span id="nav-spacer" style="flex:1"></span>
        {nav_stats}
    </div>
    """, unsafe_allow_html=True)

    # Render clickable nav buttons in a compact horizontal strip
    btn_cols = st.columns(len(NAV_PAGES) + 2)  # +2 for logo space + right padding
    for i, pg in enumerate(NAV_PAGES):
        is_active = st.session_state.page == pg
        # Wrap active button in styled div
        with btn_cols[i + 1]:
            if is_active:
                st.markdown(f'<div class="nav-active">', unsafe_allow_html=True)
            if st.button(pg, key=f"nav_{pg}", use_container_width=True):
                st.session_state.page = pg
                # Clear shared time window when navigating away from analyse
                if pg != "📊 Analyse":
                    st.session_state.pop("shared_tw_t0", None)
                    st.session_state.pop("shared_tw_t1", None)
                st.rerun()
            if is_active:
                st.markdown('</div>', unsafe_allow_html=True)

    st.markdown("---")

    # ── Thresholds (collapsible, always accessible) ──────────────────────────
    with st.sidebar:
        st.markdown('<div class="logo-area">⚡ FAMEL</div><div class="logo-sub">Electric Moto Telemetry</div>', unsafe_allow_html=True)
        st.divider()
        st.markdown("**⚙️ Thresholds**")
        thr = {}
        for ch, cfg in DEFAULT_THR.items():
            lbl=CHANNELS.get(ch,ch); hi=cfg["dir"]=="high"
            thr[ch] = {
                "warn": st.number_input(f'{lbl} {"↑W" if hi else "↓W"}',value=float(cfg["warn"]),key=f'w_{ch}',step=1.0),
                "crit": st.number_input(f'{lbl} {"↑C" if hi else "↓C"}',value=float(cfg["crit"]),key=f'c_{ch}',step=1.0),
                "dir":  cfg["dir"]
            }

    # ── Route to page ────────────────────────────────────────────────────────
    page = st.session_state.page
    if   page == "📤 Upload":   page_upload()
    elif page == "📋 Sessions":  page_sessions()
    elif page == "📊 Analyse":   page_analyse(thr)
    elif page == "🔄 Compare":   page_compare(thr)
    elif page == "🏍️ Paddock":  page_paddock()
    elif page == "⚙️ AI Config": page_ai_instructions()

    # ── Floating AI chat (always rendered at bottom) ─────────────────────────
    st.markdown("<br><br>", unsafe_allow_html=True)
    render_floating_ai()


if __name__ == "__main__":
    main()
